import React, { useEffect } from 'react';
import styled from 'styled-components';
import { useTheme } from '../context/ThemeContext';
import { PageWrapper, ContentContainer, Section, Header } from '../components/common/PageWrapper';
import Footer from '../components/Footer';
import AOS from 'aos';
import 'aos/dist/aos.css';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faInstagram, faLinkedinIn } from '@fortawesome/free-brands-svg-icons';

const TeamContainer = styled.div`
  min-height: 100vh;
  background: ${props => props.theme.background};
  padding-top: 80px;
  transition: background-color 0.3s ease;
`;

const TeamSection = styled.section`
  padding: 100px 10%;
`;

const HeaderStyled = styled.div`
  text-align: center;
  margin-bottom: 60px;

  h2 {
    font-size: 3rem;
    color: ${props => props.theme.primary};
    margin-bottom: 20px;
    position: relative;
    display: inline-block;

    &::after {
      content: '';
      position: absolute;
      bottom: -10px;
      left: 50%;
      transform: translateX(-50%);
      width: 80px;
      height: 4px;
      background: linear-gradient(
        to right,
        ${props => props.theme.primary},
        ${props => props.theme.secondary}
      );
      border-radius: 2px;
    }
  }
`;

const TeamGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 30px;
`;

const TeamMemberContent = styled.div`
  text-align: left;
  padding: 0 20px;
`;

const SocialLinks = styled.div`
  display: flex;
  gap: 20px;
  margin-top: 15px;
  justify-content: flex-start;

  a {
    color: ${props => props.theme.primary};
    font-size: 1.5rem;
    transition: all 0.3s ease;
    display: flex;
    align-items: center;
    gap: 8px;
    text-decoration: none;

    &:hover {
      transform: translateY(-3px);
      color: ${props => props.theme.hoverColor};
    }
  }
`;

const GalleryContainer = styled.div`
  min-height: 100vh;
  background: ${props => props.theme.background};
  padding-top: 80px;
  transition: background-color 0.3s ease;
`;

const GalleryGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 25px;
  padding: 20px;
`;

const GalleryCard = styled.div`
  background: ${props => props.theme.cardBackground};
  border: 1px solid ${props => props.theme.cardBorder};
  border-radius: 15px;
  overflow: hidden;
  transition: all 0.3s ease;

  img {
    width: 100%;
    height: 300px;
    object-fit: cover;
  }

  &:hover {
    transform: translateY(-5px);
    box-shadow: ${props => props.theme.shadow};
  }
`;

const Team = () => {
  const { theme } = useTheme();

  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: true
    });
  }, []);

  const teamMembers = [
    {
      name: "Charchit",
      position: "CEO & Founder",
      image: require("../assets/team/charchit1.jpeg"),
      instagram: "https://www.instagram.com/charchit.singh_16/",
      linkedin: "#"
    },
    {
      name: "Ayush Samant",
      position: "COO",
      image: require("../assets/team/ayush_samant.jpg"),
      instagram: "#",
      linkedin: "#"
    },
    {
      name: "Neelansh",
      position: "COO",
      image: require("../assets/team/neelansh.jpeg"),
      instagram: "https://www.instagram.com/neelansh_pratap_singh?igsh=bmRzZW5sb2w0dmRi",
      linkedin: "https://www.linkedin.com/in/neelansh-singh-894852218?utm_source=share&utm_campaign=share_via&utm_content=profile&utm_medium=android_app"
    },
    {
      name: "Mayank",
      position: "Marketing Head",
      image: require("../assets/team/mayank.jpeg"),
      instagram: "https://www.instagram.com/m01ayank0?igsh=cDZvd2JncTBmam5s",
      linkedin: "https://www.linkedin.com/in/mayank-dhusia-807b3335a?utm_source=share&utm_campaign=share_via&utm_content=profile&utm_medium=android_app"
    },
    {
      name: "Piyush Saini",
      position: "Technical Lead",
      image: require("../assets/team/piyush.jpg"),
      instagram: "http://instagram.com/piyush_saini_40",
      linkedin: "https://www.linkedin.com/in/piyushsaini2004/"
    },
    {
      name: "Ayush Yadav",
      position: "Social Media Head",
      image: require("../assets/team/ayush yadav.JPEG"),
      instagram: "https://www.instagram.com/ayusx_h",
      linkedin: "https://www.linkedin.com/me?trk=p_mwlite_feed-secondary_nav"
    },
    {
      name: "Bhanu",
      position: "Media Head",
      image: require("../assets/team/bhanu_picture.jpg"),
      instagram: "https://optimusorgz.github.io/Optimusorgz/team.html#",
      linkedin: "https://optimusorgz.github.io/Optimusorgz/team.html#"
    }
  ];

  return (
    <PageWrapper theme={theme}>
      <TeamContainer theme={theme}>
        <TeamSection>
          <HeaderStyled theme={theme}>
            <h2 data-aos="fade-up">Our Team</h2>
          </HeaderStyled>
          <TeamGrid>
            {teamMembers.map((member, index) => (
              <div 
                key={index} 
                data-aos="fade-up"
                data-aos-delay={100 * (index % 4)}
              >
                <img 
                  src={member.image} 
                  alt={member.name}
                  style={{
                    width: '200px',
                    height: '200px',
                    borderRadius: '50%',
                    objectFit: 'cover',
                    marginBottom: '15px'
                  }}
                />
                <TeamMemberContent>
                  <h3 style={{ 
                    color: theme.primary,
                    margin: '0 0 5px 0',
                    fontSize: '1.5rem'
                  }}>
                    {member.name}
                  </h3>
                  <p style={{ 
                    color: theme.text,
                    margin: '0 0 10px 0',
                    fontSize: '1.1rem'
                  }}>
                    {member.position}
                  </p>
                  <SocialLinks theme={theme}>
                    <a 
                      href={member.instagram} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      title={`${member.name}'s Instagram`}
                    >
                      <FontAwesomeIcon icon={faInstagram} />
                    </a>
                    <a 
                      href={member.linkedin} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      title={`${member.name}'s LinkedIn`}
                    >
                      <FontAwesomeIcon icon={faLinkedinIn} />
                    </a>
                  </SocialLinks>
                </TeamMemberContent>
              </div>
            ))}
          </TeamGrid>
        </TeamSection>
        <Footer />
      </TeamContainer>
    </PageWrapper>
  );
};

const Gallery = () => {
  const { theme } = useTheme();

  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: true
    });
  }, []);

  const images = [
    { src: 'IMG_0317.jpg', alt: 'Team Building Activity' },
    { src: 'IMG_0325.jpg', alt: 'Workshop Session' },
    { src: 'IMG_0331.jpg', alt: 'Group Discussion' },
    { src: 'IMG_0341.jpg', alt: 'Team Presentation' },
    { src: 'IMG_0358.jpg', alt: 'Project Review' },
    { src: 'IMG_5760.jpeg', alt: 'Team Meeting' },
    { src: 'IMG_5766.JPG', alt: 'Brainstorming Session' },
    { src: 'IMG_5773.JPG', alt: 'Tech Talk' },
    { src: 'IMG_5780.JPG', alt: 'Team Collaboration' },
    { src: 'IMG_0314.jpg', alt: 'Innovation Workshop' },
    { src: 'IMG_0322.jpg', alt: 'Team Event' },
    { src: 'IMG_0333.jpg', alt: 'Project Planning' },
    { src: 'IMG_0338.jpg', alt: 'Team Discussion' },
    { src: 'IMG_0352.jpg', alt: 'Development Session' }
  ];

  return (
    <PageWrapper theme={theme}>
      <GalleryContainer theme={theme}>
        <Section>
          <Header theme={theme}>
            <h2 data-aos="fade-up">Our Gallery</h2>
          </Header>
          <GalleryGrid>
            {images.map((image, index) => (
              <GalleryCard 
                key={index} 
                theme={theme}
                data-aos="fade-up"
                data-aos-delay={100 * (index % 4)}
              >
                <img 
                  src={require(`../assets/${image.src}`)} 
                  alt={image.alt}
                  loading="lazy"
                />
              </GalleryCard>
            ))}
          </GalleryGrid>
        </Section>
        <Footer />
      </GalleryContainer>
    </PageWrapper>
  );
};

export { Team, Gallery };
